class Solution {
public:
    bool solve(vector<int>& nums) {
        int n = nums.size();
        for (int i = 0; i < n - 1; i++) {
            if (nums[i] > nums[i + 1]) 
                std::swap(nums[i], nums[i + 1]);
        }
        return true;
    }
};

int main() {
