    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> nums(n);
        for (int i = 0; i < n; i++)
            std::cin >> nums[i];
        Solution s;
        std::cout << (s.solve(nums) ? '1' : '0') << std::endl;
    }
    return 0;
}
